import { Scale } from "lucide-react";
import { getFirmBranding } from "@/lib/queries/settings";

export default async function AuthLayout({ children }: { children: React.ReactNode }) {
  const branding = await getFirmBranding();

  return (
    <div className="relative flex min-h-screen items-center justify-center px-4">
      {/* Background */}
      <div className="absolute inset-0 -z-10">
        <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-background to-amber-500/5" />
        <div className="absolute right-0 top-0 h-[500px] w-[500px] rounded-full bg-primary/5 blur-3xl" />
        <div className="absolute bottom-0 left-0 h-[400px] w-[400px] rounded-full bg-amber-500/5 blur-3xl" />
      </div>

      <div className="w-full max-w-md">
        <div className="mb-8 flex flex-col items-center text-center">
          {branding.logoUrl ? (
            <img
              src={branding.logoUrl}
              alt={branding.firmName ?? "Firm logo"}
              className="mb-3 h-12 w-12 rounded-xl object-contain"
            />
          ) : (
            <div className="mb-3 flex h-12 w-12 items-center justify-center rounded-xl bg-primary shadow-lg">
              <Scale className="h-6 w-6 text-primary-foreground" />
            </div>
          )}
          <h1 className="text-xl font-bold tracking-tight">
            {branding.firmName ?? "Law Firm Registry"}
          </h1>
          <p className="mt-1 text-xs text-muted-foreground">
            Legal Practice Management System
          </p>
        </div>
        {children}
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import Link from "next/link";
import { requireAuth } from "@/lib/auth/get-session";
import { AdminDashboard } from "@/components/dashboard/admin-dashboard";
import { AttorneyDashboard } from "@/components/dashboard/attorney-dashboard";
import { Button } from "@/components/ui/button";
import { Briefcase, Plus, FileText, Users } from "lucide-react";

export const metadata: Metadata = {
  title: "Dashboard",
  description: "Overview of your law firm operations",
};

export default async function DashboardPage() {
  const session = await requireAuth();
  const name = session.user?.name ?? "User";
  const role = session.user?.role as string;
  const userId = session.user?.id as string;

  const hour = new Date().getHours();
  const greeting =
    hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";

  return (
    <div className="space-y-6">
      {/* Welcome Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">
            {greeting}, {name}
          </h1>
          <p className="text-sm text-muted-foreground">
            Here&apos;s what&apos;s happening at your firm today.
          </p>
        </div>
        {role === "admin" && (
          <div className="flex items-center gap-2">
            <Button size="sm" variant="outline" className="gap-1.5" asChild>
              <Link href="/clients/new">
                <Users className="h-3.5 w-3.5" />
                New Client
              </Link>
            </Button>
            <Button size="sm" className="gap-1.5" asChild>
              <Link href="/cases/new">
                <Plus className="h-3.5 w-3.5" />
                New Case
              </Link>
            </Button>
          </div>
        )}
      </div>

      {role === "admin" ? (
        <AdminDashboard />
      ) : role === "attorney" ? (
        <AttorneyDashboard userId={userId} />
      ) : (
        <div className="space-y-6">
          <p className="text-muted-foreground">Welcome to the Law Firm Registry.</p>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  useReactTable,
  getCoreRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  getFilteredRowModel,
  flexRender,
  type SortingState,
} from "@tanstack/react-table";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { attorneyColumns, type AttorneyRow } from "./attorney-columns";

interface AttorneyDataTableProps {
  data: AttorneyRow[];
}

export function AttorneyDataTable({ data }: AttorneyDataTableProps) {
  const router = useRouter();
  const [sorting, setSorting] = useState<SortingState>([]);
  const [globalFilter, setGlobalFilter] = useState("");

  const table = useReactTable({
    data,
    columns: attorneyColumns,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onSortingChange: setSorting,
    onGlobalFilterChange: setGlobalFilter,
    state: { sorting, globalFilter },
  });

  return (
    <div className="space-y-4">
      <Input
        placeholder="Search attorneys..."
        value={globalFilter}
        onChange={(e) => setGlobalFilter(e.target.value)}
        className="max-w-sm"
      />
      <div className="rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  className="cursor-pointer"
                  onClick={(e) => {
                    if ((e.target as HTMLElement).closest("a, button")) return;
                    router.push(`/attorneys/${row.original.id}`);
                  }}
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={attorneyColumns.length} className="h-24 text-center">
                  No attorneys found.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
      <div className="flex items-center justify-end gap-2">
        <Button
          variant="outline"
          size="sm"
          onClick={() => table.previousPage()}
          disabled={!table.getCanPreviousPage()}
        >
          Previous
        </Button>
        <Button
          variant="outline"
          size="sm"
          onClick={() => table.nextPage()}
          disabled={!table.getCanNextPage()}
        >
          Next
        </Button>
      </div>
    </div>
  );
}

