"use client";

import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import { createQuoteWithLineItemsSchema, type CreateQuoteWithLineItemsInput } from "@/lib/validators/billing";
import { createQuoteWithLineItems } from "@/lib/actions/billing";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Card, CardContent } from "@/components/ui/card";
import { Plus, Trash2 } from "lucide-react";

interface QuoteFormProps {
  cases: { id: string; caseNumber: string; title: string }[];
  clients: { id: string; name: string }[];
}

export function QuoteForm({ cases, clients }: QuoteFormProps) {
  const router = useRouter();

  const form = useForm<CreateQuoteWithLineItemsInput>({
    resolver: zodResolver(createQuoteWithLineItemsSchema),
    defaultValues: {
      caseId: undefined,
      clientId: "",
      validUntil: "",
      notes: "",
      lineItems: [{ description: "", quantity: 1, rate: 0, amount: 0 }],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "lineItems",
  });

  const watchLineItems = form.watch("lineItems");

  function updateLineItemAmount(index: number) {
    const quantity = form.getValues(`lineItems.${index}.quantity`) || 0;
    const rate = form.getValues(`lineItems.${index}.rate`) || 0;
    form.setValue(`lineItems.${index}.amount`, quantity * rate);
  }

  const subtotal = watchLineItems.reduce((sum, item) => sum + (item.amount || 0), 0);
  const vatAmount = subtotal * 0.16;
  const total = subtotal + vatAmount;

  async function onSubmit(data: CreateQuoteWithLineItemsInput) {
    try {
      const dataWithAmounts = {
        ...data,
        lineItems: data.lineItems.map((item) => ({
          ...item,
          amount: item.quantity * item.rate,
        })),
      };

      const result = await createQuoteWithLineItems(dataWithAmounts);

      if (result.error) {
        toast.error(result.error);
        return;
      }

      toast.success("Quote created");
      router.push("/billing/quotes");
      router.refresh();
    } catch {
      toast.error("An unexpected error occurred");
    }
  }

  return (
    <Card className="shadow-sm">
      <CardContent className="pt-6">
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Client *</Label>
              <Select
                value={form.watch("clientId")}
                onValueChange={(val) => form.setValue("clientId", val)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select client" />
                </SelectTrigger>
                <SelectContent>
                  {clients.map((c) => (
                    <SelectItem key={c.id} value={c.id}>
                      {c.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {form.formState.errors.clientId && (
                <p className="text-sm text-destructive">{form.formState.errors.clientId.message}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label>Case (optional)</Label>
              <Select
                value={form.watch("caseId") ?? ""}
                onValueChange={(val) => form.setValue("caseId", val || undefined)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select case (optional)" />
                </SelectTrigger>
                <SelectContent>
                  {cases.map((c) => (
                    <SelectItem key={c.id} value={c.id}>
                      {c.caseNumber} - {c.title}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="validUntil">Valid Until *</Label>
              <Input id="validUntil" type="date" {...form.register("validUntil")} />
              {form.formState.errors.validUntil && (
                <p className="text-sm text-destructive">{form.formState.errors.validUntil.message}</p>
              )}
            </div>
          </div>

          {/* Line Items */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label className="text-base font-semibold">Line Items *</Label>
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => append({ description: "", quantity: 1, rate: 0, amount: 0 })}
              >
                <Plus className="h-3.5 w-3.5 mr-1.5" />
                Add Item
              </Button>
            </div>

            {form.formState.errors.lineItems?.root && (
              <p className="text-sm text-destructive">{form.formState.errors.lineItems.root.message}</p>
            )}

            {fields.map((field, index) => (
              <div key={field.id} className="rounded-lg border p-4 space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium text-muted-foreground">Item {index + 1}</span>
                  {fields.length > 1 && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => remove(index)}
                    >
                      <Trash2 className="h-3.5 w-3.5 text-destructive" />
                    </Button>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor={`lineItems.${index}.description`}>Description *</Label>
                  <Input
                    id={`lineItems.${index}.description`}
                    {...form.register(`lineItems.${index}.description`)}
                    placeholder="Service description"
                  />
                  {form.formState.errors.lineItems?.[index]?.description && (
                    <p className="text-sm text-destructive">
                      {form.formState.errors.lineItems[index].description?.message}
                    </p>
                  )}
                </div>

                <div className="grid gap-4 md:grid-cols-3">
                  <div className="space-y-2">
                    <Label htmlFor={`lineItems.${index}.quantity`}>Quantity</Label>
                    <Input
                      id={`lineItems.${index}.quantity`}
                      type="number"
                      step="0.01"
                      min="0.01"
                      {...form.register(`lineItems.${index}.quantity`, {
                        valueAsNumber: true,
                        onChange: () => updateLineItemAmount(index),
                      })}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor={`lineItems.${index}.rate`}>Rate (KES)</Label>
                    <Input
                      id={`lineItems.${index}.rate`}
                      type="number"
                      step="0.01"
                      min="0"
                      {...form.register(`lineItems.${index}.rate`, {
                        valueAsNumber: true,
                        onChange: () => updateLineItemAmount(index),
                      })}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label>Amount (KES)</Label>
                    <Input
                      readOnly
                      value={(watchLineItems[index]?.amount || 0).toLocaleString("en-KE", {
                        minimumFractionDigits: 2,
                      })}
                      className="bg-muted"
                    />
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Totals */}
          <div className="rounded-lg border bg-muted/50 p-4 space-y-2">
            <div className="flex justify-between text-sm">
              <span>Subtotal</span>
              <span>KES {subtotal.toLocaleString("en-KE", { minimumFractionDigits: 2 })}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span>VAT (16%)</span>
              <span>KES {vatAmount.toLocaleString("en-KE", { minimumFractionDigits: 2 })}</span>
            </div>
            <div className="flex justify-between font-semibold border-t pt-2">
              <span>Total</span>
              <span>KES {total.toLocaleString("en-KE", { minimumFractionDigits: 2 })}</span>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="notes">Notes</Label>
            <Textarea id="notes" rows={3} {...form.register("notes")} placeholder="Additional notes (optional)" />
            {form.formState.errors.notes && (
              <p className="text-sm text-destructive">{form.formState.errors.notes.message}</p>
            )}
          </div>

          <div className="flex gap-4">
            <Button type="submit" disabled={form.formState.isSubmitting}>
              {form.formState.isSubmitting ? "Creating..." : "Create Quote"}
            </Button>
            <Button type="button" variant="outline" onClick={() => router.back()}>
              Cancel
            </Button>
          </div>
        </form>
      </CardContent>
    </Card>
  );
}

"use client";

import { useRouter } from "next/navigation";
import { RowActionsMenu, type RowAction } from "@/components/shared/row-actions-menu";
import { useAction } from "@/hooks/use-action";
import { updateQuoteStatus } from "@/lib/actions/billing";
import { Send, CheckCircle, XCircle, Clock } from "lucide-react";

interface QuoteRowActionsProps {
  quoteId: string;
  status: string;
  userRole: string;
}

export function QuoteRowActions({ quoteId, status, userRole }: QuoteRowActionsProps) {
  const router = useRouter();

  const { execute: executeSend, isPending: isSending } = useAction(
    (id: string) => updateQuoteStatus(id, "sent"),
    { successMessage: "Quote sent", onSuccess: () => router.refresh() }
  );

  const { execute: executeAccept, isPending: isAccepting } = useAction(
    (id: string) => updateQuoteStatus(id, "accepted"),
    { successMessage: "Quote accepted", onSuccess: () => router.refresh() }
  );

  const { execute: executeReject, isPending: isRejecting } = useAction(
    (id: string) => updateQuoteStatus(id, "rejected"),
    { successMessage: "Quote rejected", onSuccess: () => router.refresh() }
  );

  const { execute: executeExpire, isPending: isExpiring } = useAction(
    (id: string) => updateQuoteStatus(id, "expired"),
    { successMessage: "Quote expired", onSuccess: () => router.refresh() }
  );

  const actions: RowAction[] = [];

  if (status === "draft") {
    actions.push({
      label: "Send Quote",
      icon: Send,
      onClick: () => executeSend(quoteId),
      disabled: isSending,
    });
  }

  if (status === "sent") {
    actions.push({
      label: "Mark Accepted",
      icon: CheckCircle,
      onClick: () => executeAccept(quoteId),
      disabled: isAccepting,
    });
    actions.push({
      label: "Mark Rejected",
      icon: XCircle,
      onClick: () => executeReject(quoteId),
      disabled: isRejecting,
    });
    actions.push({
      label: "Mark Expired",
      icon: Clock,
      onClick: () => executeExpire(quoteId),
      disabled: isExpiring,
    });
  }

  return <RowActionsMenu actions={actions} />;
}

"use client";

import { useState } from "react";
import { format } from "date-fns";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { Clock, MapPin, ExternalLink, Trash2, Plus, Gavel } from "lucide-react";
import { formatEnum } from "@/lib/utils/format-enum";
import { getBadgeStyle, getBlockColor } from "./event-type-colors";
import { deleteEvent } from "@/lib/actions/calendar";
import type { CalendarEvent } from "./calendar-types";
import { APP_LOCALE } from "@/lib/constants/locale";
import Link from "next/link";

const capsule =
  "inline-flex items-center gap-1 rounded-full px-2.5 py-0.5 text-[11px] font-semibold leading-none whitespace-nowrap";

/** Map event type to a left border color class */
function getLeftBorderColor(type: string): string {
  const map: Record<string, string> = {
    court_hearing: "border-l-red-500",
    meeting: "border-l-blue-500",
    deposition: "border-l-purple-500",
    deadline: "border-l-rose-500",
    reminder: "border-l-slate-400",
    consultation: "border-l-teal-500",
    mediation: "border-l-amber-500",
    arbitration: "border-l-indigo-500",
    filing_deadline: "border-l-orange-500",
    client_meeting: "border-l-cyan-500",
    internal_meeting: "border-l-sky-500",
    court_mention: "border-l-pink-500",
    site_visit: "border-l-emerald-500",
    training: "border-l-violet-500",
    other: "border-l-slate-400",
  };
  return map[type] ?? map.other;
}

interface CalendarDaySheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  date: Date | null;
  events: CalendarEvent[];
}

export function CalendarDaySheet({
  open,
  onOpenChange,
  date,
  events,
}: CalendarDaySheetProps) {
  const router = useRouter();
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [deleting, setDeleting] = useState(false);

  function handleClose(val: boolean) {
    if (!val) {
      setSelectedEvent(null);
    }
    onOpenChange(val);
  }

  async function handleDelete(eventId: string) {
    setDeleting(true);
    try {
      const result = await deleteEvent(eventId);
      if (result?.error) {
        toast.error(result.error);
      } else {
        toast.success("Event deleted");
        setSelectedEvent(null);
        router.refresh();
      }
    } catch {
      toast.error("Failed to delete event");
    } finally {
      setDeleting(false);
    }
  }

  if (!date) return null;

  const sortedEvents = [...events].sort(
    (a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime()
  );

  return (
    <Sheet open={open} onOpenChange={handleClose}>
      <SheetContent side="right" className="w-full sm:max-w-md">
        <SheetHeader>
          <SheetTitle>{format(date, "EEEE, MMMM d, yyyy")}</SheetTitle>
          <SheetDescription>
            {sortedEvents.length} event{sortedEvents.length !== 1 ? "s" : ""}
          </SheetDescription>
        </SheetHeader>

        <div className="px-4">
          <Button size="sm" asChild className="w-full">
            <Link href={`/calendar/new`}>
              <Plus className="h-3.5 w-3.5 mr-1.5" />
              Add Event
            </Link>
          </Button>
        </div>

        <ScrollArea className="flex-1 px-4 pb-4">
          {sortedEvents.length === 0 ? (
            <p className="py-8 text-center text-sm text-muted-foreground">
              No events on this day.
            </p>
          ) : selectedEvent ? (
            /* Event Detail View */
            <div className="space-y-4">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedEvent(null)}
                className="mb-2"
              >
                &larr; Back to list
              </Button>

              <div className={`rounded-lg border bg-card p-4 shadow-sm border-l-4 ${getLeftBorderColor(selectedEvent.type)}`}>
                <h3 className="text-base font-semibold">{selectedEvent.title}</h3>
                <div className="mt-2 flex flex-wrap items-center gap-2">
                  <span className={`${capsule} ${getBadgeStyle(selectedEvent.type)}`}>
                    {formatEnum(selectedEvent.type)}
                  </span>
                  {selectedEvent.isCourtDate && (
                    <span className={`${capsule} bg-red-50 text-red-700 ring-1 ring-inset ring-red-600/20`}>
                      <Gavel className="h-3 w-3" />
                      Court Date
                    </span>
                  )}
                </div>

                <Separator className="my-3" />

                <div className="space-y-3 text-sm">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Clock className="h-4 w-4 shrink-0" />
                    {selectedEvent.allDay ? (
                      <span>All day</span>
                    ) : (
                      <span>
                        {new Date(selectedEvent.startTime).toLocaleTimeString(APP_LOCALE, {
                          hour: "2-digit",
                          minute: "2-digit",
                        })}{" "}
                        &ndash;{" "}
                        {new Date(selectedEvent.endTime).toLocaleTimeString(APP_LOCALE, {
                          hour: "2-digit",
                          minute: "2-digit",
                        })}
                      </span>
                    )}
                  </div>

                  {selectedEvent.location && (
                    <div className="flex items-center gap-2 text-muted-foreground">
                      <MapPin className="h-4 w-4 shrink-0" />
                      <span>{selectedEvent.location}</span>
                    </div>
                  )}

                  {selectedEvent.caseId && (
                    <div className="flex items-center gap-2">
                      <ExternalLink className="h-4 w-4 shrink-0 text-muted-foreground" />
                      <Link
                        href={`/cases/${selectedEvent.caseId}`}
                        className="text-sm text-primary hover:underline"
                      >
                        View linked case
                      </Link>
                    </div>
                  )}
                </div>
              </div>

              <div className="flex gap-2">
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={() => handleDelete(selectedEvent.id)}
