              ))}
            </div>
          )}
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
}

"use client";

import { useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Calendar, Clock, AlertTriangle } from "lucide-react";
import { formatEnum } from "@/lib/utils/format-enum";
import { APP_LOCALE } from "@/lib/constants/locale";
import { cn } from "@/lib/utils";
import { getDotColor, getBadgeStyle } from "./event-type-colors";
import { CalendarDaySheet } from "./calendar-day-sheet";
import { PriorityBadge } from "@/components/shared/status-badges";
import type { SerializedCalendarEvent } from "./calendar-types";
import { deserializeEvents, type CalendarEvent } from "./calendar-types";

interface Deadline {
  id: string;
  title: string;
  priority: string;
  dueDate: Date;
  completedAt: Date | null;
  isStatutory: boolean;
  caseNumber: string | null;
  assignedToName: string | null;
}

interface CalendarViewProps {
  events: SerializedCalendarEvent[];
  deadlines: Deadline[];
}

const capsule =
  "inline-flex items-center gap-1 rounded-full px-2.5 py-0.5 text-[11px] font-semibold leading-none whitespace-nowrap";

export function CalendarView({ events: serializedEvents, deadlines }: CalendarViewProps) {
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);
  const [sheetOpen, setSheetOpen] = useState(false);

  const events = useMemo(() => deserializeEvents(serializedEvents), [serializedEvents]);

  const upcomingEvents = events
    .filter((e) => new Date(e.startTime) >= new Date())
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    .slice(0, 20);

  const pendingDeadlines = deadlines
    .filter((d) => !d.completedAt)
    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  function handleEventClick(event: CalendarEvent) {
    const day = new Date(event.startTime);
    // Get all events for the same day
    setSelectedDay(day);
    setSheetOpen(true);
  }

  /** Get all events for the selected day */
  const selectedDayEvents = useMemo(() => {
    if (!selectedDay) return [];
    return events.filter((e) => {
      const eventDay = new Date(e.startTime);
      return (
        eventDay.getFullYear() === selectedDay.getFullYear() &&
        eventDay.getMonth() === selectedDay.getMonth() &&
        eventDay.getDate() === selectedDay.getDate()
      );
    });
  }, [events, selectedDay]);

  return (
    <>
      <div className="grid gap-6 md:grid-cols-2">
        <Card className="shadow-sm">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="h-5 w-5" />
              Upcoming Events
            </CardTitle>
          </CardHeader>
          <CardContent>
            {upcomingEvents.length === 0 ? (
              <p className="text-sm text-muted-foreground">No upcoming events.</p>
            ) : (
              <div className="space-y-3">
                {upcomingEvents.map((event) => (
                  <button
                    key={event.id}
                    onClick={() => handleEventClick(event)}
                    className="flex w-full items-start gap-3 border-b pb-3 last:border-0 transition-colors hover:bg-muted/50 rounded-md px-2 -mx-2 py-1 text-left"
                  >
                    <div className="mt-1.5 flex items-center gap-1.5">
                      <span
                        className={cn(
                          "inline-block h-2.5 w-2.5 rounded-full",
                          getDotColor(event.type)
                        )}
                      />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-sm">{event.title}</p>
                      <div className="flex items-center gap-2 mt-1 flex-wrap">
                        <span className="text-xs text-muted-foreground">
                          {new Date(event.startTime).toLocaleString(APP_LOCALE, {
                            dateStyle: "medium",
                            timeStyle: "short",
                          })}
                        </span>
                        {event.isCourtDate && (
                          <span className={`${capsule} bg-red-50 text-red-700 ring-1 ring-inset ring-red-600/20`}>
                            Court
                          </span>
                        )}
                        <span className={`${capsule} ${getBadgeStyle(event.type)}`}>
                          {formatEnum(event.type)}
                        </span>
                      </div>
                      {event.location && (
                        <p className="text-xs text-muted-foreground mt-1">{event.location}</p>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <Card className="shadow-sm">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5" />
              Pending Deadlines
            </CardTitle>
          </CardHeader>
          <CardContent>
            {pendingDeadlines.length === 0 ? (
              <p className="text-sm text-muted-foreground">No pending deadlines.</p>
            ) : (
              <div className="space-y-3">
                {pendingDeadlines.map((dl) => {
                  const isOverdue = new Date(dl.dueDate) < new Date();
                  return (
                    <div
                      key={dl.id}
                      className={`flex items-start justify-between border-b pb-3 last:border-0 transition-colors hover:bg-muted/50 rounded-md px-2 -mx-2 py-1 ${
                        isOverdue ? "text-destructive" : ""
                      }`}
                    >
                      <div>
                        <p className="font-medium text-sm">{dl.title}</p>
                        <div className="flex items-center gap-2 mt-1 flex-wrap">
                          <span className="text-xs text-muted-foreground">
                            Due: {new Date(dl.dueDate).toLocaleDateString(APP_LOCALE)}
                          </span>
                          {dl.caseNumber && (
                            <span className="text-xs font-mono text-muted-foreground">
                              {dl.caseNumber}
                            </span>
                          )}
                          {dl.isStatutory && (
                            <span className={`${capsule} bg-rose-50 text-rose-700 ring-1 ring-inset ring-rose-600/20`}>
                              Statutory
                            </span>
                          )}
                        </div>
                      </div>
                      <PriorityBadge priority={dl.priority} />
                    </div>
                  );
                })}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <CalendarDaySheet
        open={sheetOpen}
        onOpenChange={setSheetOpen}
        date={selectedDay}
        events={selectedDayEvents}
      />
    </>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  useReactTable,
  getCoreRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  getFilteredRowModel,
  flexRender,
  type SortingState,
  type ColumnFiltersState,
} from "@tanstack/react-table";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Card } from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { EmptyState } from "@/components/shared/empty-state";
import { caseColumns, type CaseRow } from "./case-columns";
import { Search, X, Briefcase } from "lucide-react";
import { formatEnum } from "@/lib/utils/format-enum";

const ALL_VALUE = "__all__";

const STATUS_OPTIONS = ["open", "in_progress", "hearing", "resolved", "closed", "archived"];
const PRIORITY_OPTIONS = ["low", "medium", "high", "urgent"];

interface CaseDataTableProps {
  data: CaseRow[];
}

export function CaseDataTable({ data }: CaseDataTableProps) {
  const router = useRouter();
  const [sorting, setSorting] = useState<SortingState>([]);
  const [globalFilter, setGlobalFilter] = useState("");
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);

  const table = useReactTable({
    data,
    columns: caseColumns,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onSortingChange: setSorting,
    onGlobalFilterChange: setGlobalFilter,
    onColumnFiltersChange: setColumnFilters,
    state: { sorting, globalFilter, columnFilters },
  });

  const statusFilter = columnFilters.find((f) => f.id === "status")?.value as string | undefined;
  const priorityFilter = columnFilters.find((f) => f.id === "priority")?.value as string | undefined;
  const hasFilters = globalFilter || statusFilter || priorityFilter;

  function clearFilters() {
    setGlobalFilter("");
    setColumnFilters([]);
  }

  const pageIndex = table.getState().pagination.pageIndex;
  const pageCount = table.getPageCount();

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <div className="relative max-w-sm flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search cases..."
            value={globalFilter}
            onChange={(e) => setGlobalFilter(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex items-center gap-2">
          <Select
            value={statusFilter ?? ALL_VALUE}
            onValueChange={(val) => {
              setColumnFilters((prev) => {
                const next = prev.filter((f) => f.id !== "status");
                if (val !== ALL_VALUE) next.push({ id: "status", value: val });
                return next;
              });
            }}
          >
            <SelectTrigger className="w-[160px]">
              <SelectValue placeholder="All Statuses" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={ALL_VALUE}>All Statuses</SelectItem>
              {STATUS_OPTIONS.map((s) => (
                <SelectItem key={s} value={s}>
                  {formatEnum(s)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select
            value={priorityFilter ?? ALL_VALUE}
            onValueChange={(val) => {
              setColumnFilters((prev) => {
                const next = prev.filter((f) => f.id !== "priority");
                if (val !== ALL_VALUE) next.push({ id: "priority", value: val });
                return next;
              });
            }}
          >
            <SelectTrigger className="w-[160px]">
              <SelectValue placeholder="All Priorities" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={ALL_VALUE}>All Priorities</SelectItem>
              {PRIORITY_OPTIONS.map((p) => (
                <SelectItem key={p} value={p}>
                  {formatEnum(p)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {hasFilters && (
            <Button variant="ghost" size="sm" onClick={clearFilters}>
              <X className="mr-1 h-3.5 w-3.5" />
              Clear
            </Button>
          )}
        </div>
      </div>

      <Card className="shadow-sm">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id} className="bg-muted/50 hover:bg-muted/50">
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id} className="h-10">
                    {header.isPlaceholder
                      ? null
                      : flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  className="cursor-pointer transition-colors hover:bg-muted/50"
                  onClick={(e) => {
                    if ((e.target as HTMLElement).closest("a, button")) return;
                    router.push(`/cases/${row.original.id}`);
                  }}
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="py-3">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={caseColumns.length} className="h-48">
                  {hasFilters ? (
                    <EmptyState
                      icon={Search}
                      title="No matching cases"
                      description="Try adjusting your search or filter criteria."
                    />
                  ) : (
                    <EmptyState
                      icon={Briefcase}
                      title="No cases yet"
                      description="Create your first case to get started."
                      actionLabel="New Case"
                      actionHref="/cases/new"
                    />
                  )}
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </Card>

      <div className="flex items-center justify-between">
        <p className="text-sm text-muted-foreground">
          {table.getFilteredRowModel().rows.length} case(s) total
        </p>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            Previous
          </Button>
          {pageCount > 0 && (
            <span className="text-sm text-muted-foreground">
              Page {pageIndex + 1} of {pageCount}
            </span>
          )}
          <Button
            variant="outline"
            size="sm"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            Next
          </Button>
        </div>
      </div>
    </div>
  );
}

