                />
              ) : (
                <div
                  className="flex h-10 w-10 items-center justify-center rounded-lg"
                  style={{ backgroundColor: primaryColor }}
                >
                  <Scale className="h-5 w-5 text-white" />
                </div>
              )}
              <span className="text-lg font-bold">{firmName || "LFR"}</span>
            </div>
          </CardContent>
        </Card>
