"use server";

import { db } from "@/lib/db";
import { clients, conflictChecks } from "@/lib/db/schema/clients";
import { cases, caseParties } from "@/lib/db/schema/cases";
import { auth } from "@/lib/auth/auth";
import { createAuditLog } from "@/lib/utils/audit";
import { ilike, or, sql, eq } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import { safeAction } from "@/lib/utils/safe-action";

export interface ConflictResult {
  entityType: "client" | "opposing_party" | "opposing_counsel" | "case_party";
  entityName: string;
  entityId: string;
  matchType: string;
  caseReference?: string;
  severity: "none" | "low" | "medium" | "high";
}

export async function searchConflicts(query: string) {
  return safeAction(async () => {
    const session = await auth();
    if (!session?.user) return [];

    if (!query || query.length < 2) return [];

    // Only attorneys and admins can run conflict searches
    if (session.user.role === "client") return [];

    // Escape LIKE-special characters to prevent pattern injection
    const escaped = query.replace(/[%_\\]/g, "\\$&");
    const pattern = `%${escaped}%`;
    const results: ConflictResult[] = [];

    // Search clients
    const clientMatches = await db
      .select({
        id: clients.id,
        firstName: clients.firstName,
        lastName: clients.lastName,
        status: clients.status,
      })
      .from(clients)
      .where(
        or(
          ilike(clients.firstName, pattern),
          ilike(clients.lastName, pattern),
          ilike(clients.companyName, pattern)
        )
      )
      .limit(10);

    for (const c of clientMatches) {
      const name = `${c.firstName} ${c.lastName}`;
      const isExact = name.toLowerCase() === query.toLowerCase();
      results.push({
        entityType: "client",
        entityName: name,
        entityId: c.id,
        matchType: isExact ? "Exact name match" : "Partial name match",
        severity: c.status === "active" ? (isExact ? "high" : "medium") : "low",
      });
    }

    // Search opposing parties in cases
    const opposingMatches = await db
      .select({
        id: cases.id,
        caseNumber: cases.caseNumber,
        opposingParty: cases.opposingParty,
        opposingCounsel: cases.opposingCounsel,
      })
      .from(cases)
      .where(
        or(
          ilike(cases.opposingParty, pattern),
          ilike(cases.opposingCounsel, pattern)
        )
      )
      .limit(10);

    for (const c of opposingMatches) {
      if (c.opposingParty?.toLowerCase().includes(query.toLowerCase())) {
        results.push({
          entityType: "opposing_party",
          entityName: c.opposingParty!,
          entityId: c.id,
          matchType: "Opposing party match",
          caseReference: c.caseNumber,
          severity: "high",
        });
      }
      if (c.opposingCounsel?.toLowerCase().includes(query.toLowerCase())) {
        results.push({
          entityType: "opposing_counsel",
          entityName: c.opposingCounsel!,
          entityId: c.id,
          matchType: "Opposing counsel match",
          caseReference: c.caseNumber,
          severity: "high",
        });
      }
    }

    // Search case parties
    const partyMatches = await db
      .select({
        id: caseParties.id,
        name: caseParties.name,
        caseId: caseParties.caseId,
        role: caseParties.role,
      })
      .from(caseParties)
      .where(ilike(caseParties.name, pattern))
      .limit(10);

    for (const p of partyMatches) {
      results.push({
        entityType: "case_party",
        entityName: p.name,
        entityId: p.caseId,
        matchType: `Case party (${p.role})`,
        severity: "low",
      });
    }

    return results;
  });
}

export interface ConflictMatch {
  type: string;
  name: string;
  detail: string;
}

export interface ConflictCheckResult {
  hasConflict: boolean;
  matches: ConflictMatch[];
}

/**
 * Internal helper: run a conflict check against existing clients and cases.
 * Does NOT require auth — caller is responsible for authorization.
 */
export async function runConflictCheck(query: string): Promise<ConflictCheckResult> {
  if (!query || query.length < 2) return { hasConflict: false, matches: [] };

  // Escape LIKE-special characters to prevent pattern injection
  const escaped = query.replace(/[%_\\]/g, "\\$&");
  const pattern = `%${escaped}%`;
  const matches: ConflictMatch[] = [];

  // Search clients by name and company name
  const clientMatches = await db
    .select({
      id: clients.id,
      firstName: clients.firstName,
      lastName: clients.lastName,
      companyName: clients.companyName,
    })
    .from(clients)
    .where(
      or(
        ilike(clients.firstName, pattern),
        ilike(clients.lastName, pattern),
        ilike(clients.companyName, pattern)
      )
    )
    .limit(20);

  for (const c of clientMatches) {
    const name = `${c.firstName} ${c.lastName}`;
    matches.push({
      type: "client",
      name,
      detail: c.companyName
        ? `Client (${c.companyName})`
        : "Client",
    });
  }

  // Search opposing parties and opposing counsel in cases
  const caseMatches = await db
    .select({
      id: cases.id,
      caseNumber: cases.caseNumber,
      opposingParty: cases.opposingParty,
      opposingCounsel: cases.opposingCounsel,
    })
    .from(cases)
    .where(
      or(
        ilike(cases.opposingParty, pattern),
        ilike(cases.opposingCounsel, pattern)
      )
    )
    .limit(20);

  for (const c of caseMatches) {
    if (c.opposingParty?.toLowerCase().includes(query.toLowerCase())) {
      matches.push({
        type: "opposing_party",
        name: c.opposingParty!,
        detail: `Opposing party in case ${c.caseNumber}`,
      });
    }
    if (c.opposingCounsel?.toLowerCase().includes(query.toLowerCase())) {
      matches.push({
        type: "opposing_counsel",
        name: c.opposingCounsel!,
        detail: `Opposing counsel in case ${c.caseNumber}`,
      });
    }
  }

  // Search case parties
  const partyMatches = await db
    .select({
      id: caseParties.id,
      name: caseParties.name,
      caseId: caseParties.caseId,
      role: caseParties.role,
    })
    .from(caseParties)
    .where(ilike(caseParties.name, pattern))
    .limit(20);

  for (const p of partyMatches) {
    matches.push({
      type: "case_party",
      name: p.name,
      detail: `Case party (${p.role})`,
    });
  }

  return { hasConflict: matches.length > 0, matches };
}

export async function resolveConflict(
  clientId: string,
  searchQuery: string,
  result: "clear" | "potential" | "conflict_found",
  resolutionNotes?: string
) {
  return safeAction(async () => {
    const session = await auth();
    if (!session?.user) return { error: "Unauthorized" };
    if (!["admin", "attorney"].includes(session.user.role)) {
      return { error: "Unauthorized" };
    }

    // Verify client exists before creating conflict check record
    const [client] = await db
      .select({ id: clients.id })
      .from(clients)
      .where(eq(clients.id, clientId))
      .limit(1);
    if (!client) return { error: "Client not found" };

    const record = await db
      .insert(conflictChecks)
      .values({
        clientId,
        searchQuery,
        result,
        resolutionNotes,
        checkedBy: session.user.id,
      })
      .returning();

    await createAuditLog(
      session.user.id,
      "create",
      "conflict_check",
      record[0].id,
      { clientId, searchQuery, result }
    );

    revalidatePath(`/clients/${clientId}`);
    return { data: record[0] };
  });
}

"use server";

import { db } from "@/lib/db";
import { clients } from "@/lib/db/schema/clients";
import { publicIntakeSchema } from "@/lib/validators/intake";
import { revalidatePath } from "next/cache";
import { headers } from "next/headers";
import { rateLimit } from "@/lib/utils/rate-limit";
import { safeAction } from "@/lib/utils/safe-action";

export async function submitIntake(data: unknown) {
  return safeAction(async () => {
    // Rate limit: max 5 submissions per hour per IP
    const headersList = await headers();
    const ip = headersList.get("x-forwarded-for")?.split(",")[0]?.trim() ?? "unknown";
    const { success } = rateLimit(`intake:${ip}`);
    if (!success) {
      return { error: "Too many submissions. Please try again later." };
    }

    const validated = publicIntakeSchema.safeParse(data);
    if (!validated.success) {
      return { error: validated.error.issues[0].message };
    }

    const { firstName, lastName, email, phone, referralSource } = validated.data;

    const result = await db
      .insert(clients)
      .values({
        type: "individual",
        status: "prospective",
        firstName,
        lastName,
        email,
        phone,
        referralSource: referralSource || undefined,
        notes: `Intake: ${validated.data.caseType} — ${validated.data.description}`,
      })
      .returning();

    revalidatePath("/clients");
    return { success: true };
  });
}

"use server";

import { db } from "@/lib/db";
import { stageAutomations, caseAssignments, caseStageHistory } from "@/lib/db/schema/cases";
import { notifications } from "@/lib/db/schema/messaging";
import { tasks } from "@/lib/db/schema/calendar";
import { cases } from "@/lib/db/schema/cases";
import { auth } from "@/lib/auth/auth";
import { stageAutomationSchema } from "@/lib/validators/pipeline";
import { eq, and, sql } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import { safeAction } from "@/lib/utils/safe-action";

// --- Automation Execution ---

export async function executeStageAutomations(
  caseId: string,
  toStageId: string,
  fromStageId: string | null,
  userId: string
) {
  // Fetch "enter" automations for the new stage
  const enterAutomations = await db
    .select()
    .from(stageAutomations)
    .where(
      and(
        eq(stageAutomations.stageId, toStageId),
        eq(stageAutomations.triggerOn, "enter"),
        eq(stageAutomations.isActive, true)
      )
    );

  // Fetch "exit" automations for the old stage
  let exitAutomations: typeof enterAutomations = [];
  if (fromStageId) {
    exitAutomations = await db
      .select()
      .from(stageAutomations)
      .where(
        and(
          eq(stageAutomations.stageId, fromStageId),
          eq(stageAutomations.triggerOn, "exit"),
          eq(stageAutomations.isActive, true)
        )
      );
  }

  const allAutomations = [...exitAutomations, ...enterAutomations];

  for (const automation of allAutomations) {
    try {
      const config = automation.actionConfig ? JSON.parse(automation.actionConfig) : {};
      switch (automation.actionType) {
        case "send_notification":
          await executeNotificationAutomation(caseId, config, userId);
          break;
        case "create_task":
          await executeTaskAutomation(caseId, config, userId);
          break;
        case "update_status":
          await executeStatusAutomation(caseId, config);
          break;
      }
    } catch (err) {
      console.error(`[pipeline automation] Failed automation ${automation.id}:`, err);
    }
  }
}

async function executeNotificationAutomation(
  caseId: string,
  config: { title?: string; message?: string },
  _userId: string
) {
  // Get all assigned users for the case
  const assigned = await db
    .select({ userId: caseAssignments.userId })
    .from(caseAssignments)
    .where(
      and(
        eq(caseAssignments.caseId, caseId),
        sql`${caseAssignments.unassignedAt} IS NULL`
      )
    );

  if (assigned.length === 0) return;

  const title = config.title || "Pipeline stage changed";
  const message = config.message || "A case you are assigned to has moved to a new pipeline stage.";

  const values = assigned.map((a) => ({
    userId: a.userId,
    type: "info" as const,
    title,
    message,
    linkUrl: `/cases/${caseId}`,
  }));

  await db.insert(notifications).values(values);
}

async function executeTaskAutomation(
  caseId: string,
  config: { title?: string; priority?: string; dueDaysOffset?: number },
  userId: string
) {
  const dueDate = config.dueDaysOffset
    ? new Date(Date.now() + config.dueDaysOffset * 86400000)
    : undefined;

  await db.insert(tasks).values({
    title: config.title || "Follow up on pipeline stage change",
    caseId,
    createdBy: userId,
    assignedTo: userId,
    priority: (config.priority as "low" | "medium" | "high" | "critical") || "medium",
    dueDate,
  });
}

async function executeStatusAutomation(
  caseId: string,
  config: { status?: string }
) {
  if (!config.status) return;
  const validStatuses = ["open", "in_progress", "hearing", "resolved", "closed", "archived"] as const;
  if (!validStatuses.includes(config.status as typeof validStatuses[number])) return;

  await db
    .update(cases)
    .set({
      status: config.status as typeof validStatuses[number],
      updatedAt: new Date(),
    })
    .where(eq(cases.id, caseId));
}

// --- Stage Automation CRUD ---

export async function createStageAutomation(data: unknown) {
  return safeAction(async () => {
    const session = await auth();
    if (!session?.user || session.user.role !== "admin") {
      return { error: "Unauthorized" };
    }

    const validated = stageAutomationSchema.safeParse(data);
    if (!validated.success) {
      return { error: validated.error.issues[0].message };
    }

    const result = await db
      .insert(stageAutomations)
      .values(validated.data)
      .returning();

    revalidatePath("/cases/pipeline");
    return { data: result[0] };
  });
}

export async function updateStageAutomation(id: string, data: unknown) {
  return safeAction(async () => {
    const session = await auth();
    if (!session?.user || session.user.role !== "admin") {
      return { error: "Unauthorized" };
    }

    const validated = stageAutomationSchema.safeParse(data);
    if (!validated.success) {
      return { error: validated.error.issues[0].message };
    }

    await db
      .update(stageAutomations)
      .set(validated.data)
      .where(eq(stageAutomations.id, id));

    revalidatePath("/cases/pipeline");
    return { success: true };
  });
}

export async function deleteStageAutomation(id: string) {
  return safeAction(async () => {
    const session = await auth();
    if (!session?.user || session.user.role !== "admin") {
      return { error: "Unauthorized" };
    }

    await db.delete(stageAutomations).where(eq(stageAutomations.id, id));

    revalidatePath("/cases/pipeline");
    return { success: true };
  });
}

export async function getStageAutomations(stageId: string) {
  return db
    .select()
    .from(stageAutomations)
    .where(eq(stageAutomations.stageId, stageId))
    .orderBy(stageAutomations.createdAt);
}

import { pgTable, uuid, text, timestamp, numeric, integer, index } from "drizzle-orm/pg-core";
import { relations } from "drizzle-orm";
import { invoiceStatus, paymentMethod, trustAccountType, trustTransactionType, quoteStatus } from "./enums";
import { users } from "./auth";
import { cases } from "./cases";
import { clients } from "./clients";
import { timeEntries, expenses } from "./time-expenses";

export const invoices = pgTable(
  "invoices",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    invoiceNumber: text("invoice_number").notNull().unique(),
    caseId: uuid("case_id").references(() => cases.id, { onDelete: "set null" }),
    clientId: uuid("client_id")
      .notNull()
      .references(() => clients.id, { onDelete: "restrict" }),
    createdBy: uuid("created_by")
      .notNull()
      .references(() => users.id, { onDelete: "restrict" }),
    status: invoiceStatus("status").notNull().default("draft"),
    subtotal: numeric("subtotal", { precision: 14, scale: 2 }).notNull().default("0"),
    vatRate: numeric("vat_rate", { precision: 5, scale: 2 }).default("16"),
    vatAmount: numeric("vat_amount", { precision: 14, scale: 2 }).notNull().default("0"),
    totalAmount: numeric("total_amount", { precision: 14, scale: 2 }).notNull().default("0"),
    paidAmount: numeric("paid_amount", { precision: 14, scale: 2 }).notNull().default("0"),
    currency: text("currency").notNull().default("KES"),
    dueDate: timestamp("due_date", { withTimezone: true }),
    sentAt: timestamp("sent_at", { withTimezone: true }),
    paidAt: timestamp("paid_at", { withTimezone: true }),
    notes: text("notes"),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (table) => [
    index("invoices_invoice_number_idx").on(table.invoiceNumber),
    index("invoices_status_idx").on(table.status),
    index("invoices_client_id_idx").on(table.clientId),
  ]
);

export const invoiceLineItems = pgTable("invoice_line_items", {
  id: uuid("id").primaryKey().defaultRandom(),
  invoiceId: uuid("invoice_id")
    .notNull()
    .references(() => invoices.id, { onDelete: "cascade" }),
  description: text("description").notNull(),
  quantity: numeric("quantity", { precision: 10, scale: 2 }).notNull().default("1"),
  unitPrice: numeric("unit_price", { precision: 12, scale: 2 }).notNull(),
  amount: numeric("amount", { precision: 14, scale: 2 }).notNull(),
  timeEntryId: uuid("time_entry_id").references(() => timeEntries.id, { onDelete: "set null" }),
  expenseId: uuid("expense_id").references(() => expenses.id, { onDelete: "set null" }),
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
});

export const payments = pgTable("payments", {
  id: uuid("id").primaryKey().defaultRandom(),
  invoiceId: uuid("invoice_id")
    .notNull()
    .references(() => invoices.id, { onDelete: "restrict" }),
  amount: numeric("amount", { precision: 14, scale: 2 }).notNull(),
  method: paymentMethod("method").notNull(),
  reference: text("reference"),
  mpesaTransactionId: text("mpesa_transaction_id"),
  receivedBy: uuid("received_by").references(() => users.id, { onDelete: "set null" }),
  paymentDate: timestamp("payment_date", { withTimezone: true }).defaultNow().notNull(),
  notes: text("notes"),
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
});

export const trustAccounts = pgTable("trust_accounts", {
  id: uuid("id").primaryKey().defaultRandom(),
  accountName: text("account_name").notNull(),
  accountNumber: text("account_number").notNull().unique(),
  type: trustAccountType("type").notNull().default("client"),
  clientId: uuid("client_id").references(() => clients.id, { onDelete: "set null" }),
  balance: numeric("balance", { precision: 14, scale: 2 }).notNull().default("0"),
  bankName: text("bank_name"),
  branchName: text("branch_name"),
  currency: text("currency").notNull().default("KES"),
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
});

export const trustTransactions = pgTable("trust_transactions", {
  id: uuid("id").primaryKey().defaultRandom(),
  accountId: uuid("account_id")
    .notNull()
    .references(() => trustAccounts.id, { onDelete: "restrict" }),
  type: trustTransactionType("type").notNull(),
  amount: numeric("amount", { precision: 14, scale: 2 }).notNull(),
  description: text("description").notNull(),
  reference: text("reference"),
  caseId: uuid("case_id").references(() => cases.id, { onDelete: "set null" }),
  performedBy: uuid("performed_by")
    .notNull()
    .references(() => users.id, { onDelete: "restrict" }),
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
});

export const quotes = pgTable("quotes", {
  id: uuid("id").primaryKey().defaultRandom(),
  quoteNumber: text("quote_number").notNull().unique(),
  clientId: uuid("client_id")
    .notNull()
    .references(() => clients.id, { onDelete: "restrict" }),
  caseId: uuid("case_id").references(() => cases.id, { onDelete: "set null" }),
  createdBy: uuid("created_by")
