export const paymentsRelations = relations(payments, ({ one, many }) => ({
  invoice: one(invoices, { fields: [payments.invoiceId], references: [invoices.id] }),
  receivedByUser: one(users, { fields: [payments.receivedBy], references: [users.id] }),
